  Future<String> uploadFile(file) async{
    final url = 'https://s3-us-west-2.amazonaws.com/test-bucket/test-image';

    final response = await http.post(url,
        headers: {
          'Content-Type': 'application/octet-stream',
          'x-amz-acl': 'public-read'
        },
        body: file);
    return response;
  }

  Future<String> analyzeImage(file) async{
    final uri = Uri.parse('https://vision.googleapis.com');

    final credentials = GoogleCredentials.fromJson(
      {
        'type':'service_account',
        'project_id': 'google-cloud-sdk',
        'private_key_id' : '<KEY>',
