        'client_x509_cert_url':'https://www.googleapis.com/robot/v1/metadata/x509/google-cloud-sdk%40developer.gserviceaccount.com'
      }
    );

    final credentialsProvider = GoogleCredentialsProvider(credentials);

    final client = VisionClient.withCredentials(credentialsProvider, uri.toString());

    final response = await client.detectText(VisionImage.fromFile(file));

    return response;
  }

